INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_251','インフォームド採用意思決定モデル','Informed Adoption Decision Model','Rogers の採用決定プロセスに情報品質・情報源多様性・認知的負荷を組み込んだ拡張モデル。採用者が意思決定に際してどのような情報探索戦略を取るかを記述し、情報過多が採用を阻害するメカニズムを解明した。デジタル時代の情報環境への適応版として提案されている。','デジタルマーケティングの情報設計と公共イノベーション政策のコミュニケーション戦略に貢献した。','diffusion_adoption_user','C_processes','普及理論・情報行動','2003','micro','adoption','information_search_adoption','["Rogers, E.M.", "Wilson, T.D.", "Case, D.O."]','["Rogers (2003) Diffusion of Innovations 5th ed.", "Wilson (1999) Information behaviour models"]','インフォームド意思決定,情報品質,認知的負荷,採用プロセス','informed decision-making,information quality,cognitive load,adoption process'),
('inno_diff_252','スマートフォン採用の高齢者研究','Elderly Population Research on Smartphone Adoption','65歳以上の高齢者によるスマートフォン採用の障壁と促進要因を分析した研究群。身体的・認知的制約・デジタル不安・家族サポート・使いやすさが採用規定因として確認されている。シニア向けUX設計と採用促進プログラムの科学的基盤を提供した。','高齢化社会のデジタルインクルージョン政策とシニア向け製品UXデザインに貢献した。','diffusion_adoption_user','C_processes','シニア採用研究','2010','micro','adoption','age_related_adoption_barrier','["Vaportzis, E.", "Clausen, M.G.", "Gow, A.J."]','["Vaportzis et al. (2017) Older adults smartphone", "Renaud & Ramsay (2003) ICT elderly"]','高齢者,スマートフォン採用,デジタルインクルージョン,UXデザイン','elderly,smartphone adoption,digital inclusion,UX design'),
('inno_diff_253','ドローン技術採用の規制枠組み研究','Regulatory Framework Research on Drone Technology Adoption','物流・農業・インフラ点検・緊急医療でのドローン採用において規制環境が採用速度に与える影響を分析した研究群。FAAルール・EU U-space・各国空域管理規制への適応コストが採用障壁として特定されている。官民対話と規制サンドボックスの有効性も検討されている。','ドローン産業政策・空域規制設計・物流DX推進に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ドローン採用・規制研究','2016','meso','adoption','regulatory_adoption','["Chamola, V.", "Hassija, V.", "Gupta, V."]','["Chamola et al. (2020) Drone delivery survey", "Hassija et al. (2021) Drone regulations review"]','ドローン,UAV,規制採用,空域管理','drone,UAV,regulatory adoption,airspace management'),
('inno_diff_254','ロボティクス手術採用の外科医研究','Surgeon Adoption Research on Robotic Surgery','da Vinci手術システムなどロボット支援外科手術への外科医採用を分析した研究群。習熟曲線・ハプティックフィードバック喪失・コスト対効果・病院組織の支持が採用規定因として確認されている。先駆的採用病院の成功事例分析も蓄積されている。','外科医教育プログラム・病院設備投資意思決定・医療AI倫理政策に貢献した。','diffusion_adoption_user','C_processes','医療ロボット採用研究','2005','meso','adoption','skill_learning_adoption','["Sung, G.T.", "Gill, I.S.", "Autorino, R."]','["Sung & Gill (2001) Robotic surgery", "Autorino et al. (2013) Robotic surgery outcomes"]','ロボット手術,外科医採用,習熟曲線,da Vinci','robotic surgery,surgeon adoption,learning curve,da Vinci'),
('inno_diff_255','消費者のサステナブル製品採用研究','Consumer Adoption Research on Sustainable Products','有機食品・フェアトレード製品・再利用可能パッケージなどサステナブル消費財の採用行動を分析した研究群。環境態度・社会規範・支払意思額・グリーンウォッシング懸念が採用意図に影響することが示された。価値-態度-行動ギャップの解消メカニズムも検討されている。','サステナブルブランド戦略・グリーンマーケティング政策・炭素税設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','サステナブル消費研究','2005','micro','adoption','value_attitude_behavior_gap','["Vermeir, I.", "Verbeke, W.", "Carrington, M.J."]','["Vermeir & Verbeke (2006) Sustainable food", "Carrington et al. (2010) Value-attitude-behavior"]','サステナブル製品,グリーン消費,環境態度,価値-行動ギャップ','sustainable products,green consumption,environmental attitude,value-behavior gap'),
('inno_diff_256','社会的イノベーション採用と制度変化','Social Innovation Adoption and Institutional Change','社会的イノベーション（社会起業・コレクティブインパクト・ソーシャルファイナンス）の採用プロセスが既存制度をどのように変容させるかを分析した研究群。制度理論・組織場論・社会運動論を統合した枠組みが提案されている。','社会変革政策・インパクト投資・NPOのスケールアップ戦略に制度的根拠を提供した。','diffusion_adoption_user','C_processes','社会的イノベーション採用研究','2008','macro','adoption','institutional_change_adoption','["Phills, J.A.", "Mulgan, G.", "Moore, M.L."]','["Phills et al. (2008) Rediscovering Social Innovation", "Mulgan (2006) Social Innovation"]','社会的イノベーション,制度変化,コレクティブインパクト,組織場','social innovation,institutional change,collective impact,organizational field'),
('inno_diff_257','デジタルメンタルヘルスツール採用研究','Adoption Research on Digital Mental Health Tools','うつ・不安障害・PTSD向けデジタルメンタルヘルスアプリ（CBTアプリ・瞑想アプリ・危機介入チャットボット）の採用を分析した研究群。スティグマ低減・匿名性・精神科専門家不足が採用促進要因として確認されている。証拠基盤の薄さと有効性懸念が主要障壁となっている。','メンタルヘルス政策のデジタル化推進と臨床心理士の補助ツール設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルメンタルヘルス採用研究','2016','micro','adoption','stigma_reduction_adoption','["Proudfoot, J.", "Nicholas, J.", "Lal, S."]','["Proudfoot (2013) mHealth mental health", "Lal & Adair (2014) E-mental health review"]','デジタルメンタルヘルス,CBTアプリ,スティグマ,採用障壁','digital mental health,CBT app,stigma,adoption barriers'),
('inno_diff_258','グリーンIT採用の組織研究','Organizational Research on Green IT Adoption','データセンター省エネ・仮想化・BYOD・電子廃棄物管理などグリーンIT施策の組織採用を分析した研究群。コスト削減動機・CSR目標・規制圧力・環境マネジメントシステム成熟度が採用規定因として確認されている。','企業のサステナビリティ戦略とITガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','グリーンIT採用研究','2009','meso','adoption','csr_driven_adoption','["Murugesan, S.", "Jenkin, T.A.", "Webster, J."]','["Murugesan (2008) Green IT", "Jenkin et al. (2011) Green IS adoption"]','グリーンIT,省エネ,CSR,サステナビリティ','green IT,energy efficiency,CSR,sustainability'),
('inno_diff_259','デジタル図書館・オープンアクセス採用研究','Digital Library and Open Access Adoption Research','研究者・学生・一般市民によるデジタル図書館・OAリポジトリ・プレプリントサーバー採用を分析した研究群。情報発見性・機関リポジトリの使いやすさ・学術評価とOAの緊張関係が採用規定因として確認されている。','学術情報政策・研究機関のOA戦略・図書館デジタル変革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','学術情報採用研究','2005','meso','adoption','academic_norm_adoption','["Bjork, B.C.", "Laakso, M.", "Suber, P."]','["Bjork et al. (2010) OA landscape", "Suber (2012) Open Access"]','デジタル図書館,オープンアクセス,プレプリント,学術評価','digital library,open access,preprint,academic evaluation'),
('inno_diff_260','スポーツテクノロジー採用のアスリート研究','Athlete Research on Sports Technology Adoption','GPS追跡・スポーツバイオメカニクス・ウェアラブル心拍モニターなどスポーツテクノロジーの選手・コーチ採用を分析した研究群。パフォーマンス改善への期待・プライバシー懸念・データオーナーシップ・コーチとの信頼関係が採用規定因として確認されている。','スポーツ科学の実践的応用と競技連盟のテクノロジー規定策定に貢献した。','diffusion_adoption_user','C_processes','スポーツテクノロジー採用研究','2012','micro','adoption','performance_driven_adoption','["Cummins, C.", "Orr, R.", "O''Connor, H."]','["Cummins et al. (2013) Sports wearable", "Orr et al. (2014) Technology athlete performance"]','スポーツテクノロジー,ウェアラブル,GPS追跡,アスリート採用','sports technology,wearable,GPS tracking,athlete adoption'),
('inno_diff_261','テレワーク・リモートワーク採用研究（COVID-19前後比較）','Pre/Post-COVID-19 Comparison of Telework Adoption Research','COVID-19パンデミックを契機とした強制的テレワーク移行と、その後のハイブリッドワーク定着過程を比較分析した研究群。技術的障壁・心理的安全性・仕事-家庭葛藤・マネジメントスタイルが採用継続に影響することが示された。','テレワーク政策設計・人事管理制度改革・オフィス不動産戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','テレワーク採用研究','2020','meso','adoption','forced_adoption_normalization','["Choudhury, P.", "Bloom, N.", "Wang, B."]','["Choudhury et al. (2021) WFH research", "Bloom et al. (2015) WFH experiment"]','テレワーク,リモートワーク,ハイブリッドワーク,COVID-19','telework,remote work,hybrid work,COVID-19'),
('inno_diff_262','エネルギー効率化技術採用の産業研究','Industrial Research on Energy Efficiency Technology Adoption','インバーター・省エネモーター・廃熱回収システムなど産業省エネ技術の採用規定因を分析した研究群。初期投資回収期間・エネルギー監査の有無・補助金設計・技術情報アクセスが採用に影響することが示された。','産業省エネ政策・エネルギー効率化投資促進スキーム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','産業省エネ採用研究','2007','meso','adoption','investment_payback_adoption','["Thollander, P.", "Ottosson, M.", "Rohdin, P."]','["Thollander & Ottosson (2008) Industrial energy management", "Rohdin et al. (2007) Energy efficiency barriers"]','省エネ技術,産業採用,エネルギー効率,投資回収','energy efficiency,industrial adoption,energy management,investment payback'),
('inno_diff_263','モバイルバンキング採用の発展途上国研究','Mobile Banking Adoption in Developing Countries','M-Pesa（ケニア）・bKash（バングラデシュ）など途上国モバイルマネーサービスの採用を分析した研究群。金融排除からの脱出・代理店ネットワーク・信頼形成・識字率の影響が主要テーマとなっている。ランダム化比較試験による因果識別研究も蓄積されている。','途上国の金融包摂政策・国際送金コスト削減・フィンテック規制設計に貢献した。','diffusion_adoption_user','C_processes','モバイルマネー採用研究','2009','meso','adoption','financial_inclusion_adoption','["Jack, W.", "Suri, T.", "Aker, J.C."]','["Jack & Suri (2011) Mobile money Kenya", "Aker & Mbiti (2010) Mobile phones Africa"]','モバイルバンキング,M-Pesa,金融包摂,途上国','mobile banking,M-Pesa,financial inclusion,developing countries'),
('inno_diff_264','製造業におけるAIロボット採用の雇用影響研究','Employment Impact Research of AI-Robot Adoption in Manufacturing','製造業でのロボット・AIシステム採用が労働者の雇用・賃金・スキル要求に与える影響を分析した研究群。Acemoglu & Restrepoのタスクモデルを採用文脈に適用し、補完効果と代替効果の分離を試みた研究が蓄積されている。','製造業の雇用政策・リスキリング戦略・産業ロボット規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','技術採用・労働経済研究','2017','macro','adoption','labor_displacement_adoption','["Acemoglu, D.", "Restrepo, P.", "Autor, D.H."]','["Acemoglu & Restrepo (2018) Robots and jobs", "Autor (2015) Why are there still so many jobs"]','AI採用,ロボット,雇用影響,タスクモデル','AI adoption,robots,employment impact,task model'),
('inno_diff_265','健康保険テクノロジー採用の保険者研究','Health Insurance Technology Adoption Research Among Insurers','デジタル承認プロセス・テレヘルス保険適用・ウェアラブルデータ活用などヘルスインシュアテック採用の保険会社意思決定を分析した研究群。規制整備・アクチュアリアルリスク評価・消費者プライバシーが主要テーマとなっている。','医療保険制度改革・インシュアテック規制・ヘルスデータ利活用ポリシーに貢献した。','diffusion_adoption_user','C_processes','インシュアテック採用研究','2018','meso','adoption','regulatory_compliance_adoption','["Stoeckli, E.", "Dremel, C.", "Uebernickel, F."]','["Stoeckli et al. (2018) InsurTech adoption", "Dremel et al. (2020) Digital insurance transformation"]','インシュアテック,ヘルスIT保険,テレヘルス,アクチュアリー','insurtech,health IT insurance,telehealth,actuarial'),
('inno_diff_266','LegalTech採用の法律専門家研究','Legal Professional Research on LegalTech Adoption','AI契約レビュー・Eディスカバリー・リーガルリサーチAI・自動文書作成ツールへの法律専門家採用を分析した研究群。専門職倫理規則・守秘義務・精度不信・雇用脅威認知が採用障壁として確認されている。','法律事務所のデジタル変革戦略と法曹教育・規制改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','LegalTech採用研究','2017','meso','adoption','professional_norm_adoption','["Susskind, R.", "Ashley, K.D.", "Katz, D.M."]','["Susskind (2017) Tomorrow''s Lawyers", "Katz (2012) Quantitative legal prediction"]','LegalTech,AI契約レビュー,法律専門家,Eディスカバリー','LegalTech,AI contract review,legal professionals,e-discovery'),
('inno_diff_267','HR Techツール採用の企業研究','Enterprise Research on HR Technology Adoption','ATS（採用管理）・HRMS・AI面接・ピープルアナリティクスなどHR Techの採用を分析した研究群。CHRO権限・従業員プライバシー・アルゴリズムバイアス懸念・ROI可視化困難が採用障壁として確認されている。','HR Techベンダーの製品設計と企業の人事デジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','HRテック採用研究','2016','meso','adoption','organizational_hr_adoption','["Gueutal, H.G.", "Stone, D.L.", "Maier, C."]','["Gueutal & Stone (2005) HR systems adoption", "Stone et al. (2015) eHRM adoption"]','HRTech,ピープルアナリティクス,AI採用,アルゴリズムバイアス','HR tech,people analytics,AI recruitment,algorithmic bias'),
('inno_diff_268','ソフトウェア開発ツール採用の開発者研究','Developer Research on Software Development Tool Adoption','Git・CI/CD・コンテナ（Docker/Kubernetes）・コードレビューツールへの開発者採用を分析した研究群。コミュニティ学習・ドキュメント品質・チーム規範・DevOps文化が採用規定因として確認されている。GitHub Surveyなど大規模調査データの活用も特徴的。','DevOps/GitOps標準化と開発者教育プログラム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','開発者ツール採用研究','2013','micro','adoption','community_learning_adoption','["Bird, C.", "Nagappan, N.", "Storey, M.A."]','["Bird et al. (2011) GitHub adoption", "Storey et al. (2017) Developer tools"]','Git,CI/CD,コンテナ,DevOps,開発者採用','Git,CI/CD,containers,DevOps,developer adoption'),
('inno_diff_269','サプライチェーン可視化技術採用研究','Supply Chain Visibility Technology Adoption Research','RFID・IoTセンサー・ブロックチェーンベースのサプライチェーン可視化ツール採用を分析した研究群。パートナー間のデータ共有意欲・標準化不足・ROI不確実性・情報セキュリティが採用障壁として確認されている。','サプライチェーンレジリエンス強化と貿易デジタル化政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','サプライチェーン採用研究','2014','meso','adoption','inter_firm_adoption','["Kwon, I.W.G.", "Suh, T.", "Saberi, S."]','["Kwon & Suh (2004) Trust, commitment, value in SC", "Saberi et al. (2019) Blockchain SC"]','サプライチェーン可視化,RFID,ブロックチェーン,データ共有','supply chain visibility,RFID,blockchain,data sharing'),
('inno_diff_270','ゲーム技術採用の教育・訓練研究（シリアスゲーム）','Educational and Training Research on Serious Game Technology Adoption','軍事訓練・医学教育・消防訓練・企業研修でのシリアスゲーム採用を分析した研究群。学習没入感・現実への転移効果・コスト便益・インストラクタースキルが採用規定因として確認されている。','軍事・医療・消防・企業訓練システムの設計と教育DX政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','シリアスゲーム採用研究','2007','meso','adoption','learning_transfer_adoption','["Zyda, M.", "Prensky, M.", "Connolly, T.M."]','["Zyda (2005) Serious games", "Connolly et al. (2012) Serious games meta-analysis"]','シリアスゲーム,ゲーム学習,訓練技術採用,没入感','serious games,game-based learning,training technology adoption,immersion'),
('inno_diff_271','フードテクノロジー採用の消費者研究（代替タンパク質）','Consumer Research on Food Technology Adoption: Alternative Proteins','培養肉・昆虫食・植物性代替肉（Beyond Meat等）への消費者採用を分析した研究群。食品新奇性忌避・肉食規範・環境意識・食体験質が採用態度に影響することが示された。文化的・宗教的規範の影響も重要テーマとなっている。','代替タンパク質規制・ラベリング政策・フードテック企業の市場開拓戦略に貢献した。','diffusion_adoption_user','C_processes','フードテクノロジー採用研究','2018','micro','adoption','food_neophobia','["Slade, P.", "Wilks, M.", "Hasan, S."]','["Slade (2018) Clean meat acceptance", "Wilks & Phillips (2017) Insect food adoption"]','代替タンパク質,培養肉,昆虫食,食品新奇性忌避','alternative protein,cultivated meat,insect food,food neophobia'),
('inno_diff_272','建設テクノロジー採用研究（BIM・デジタル建設）','Construction Technology Adoption Research: BIM and Digital Construction','BIM（建築情報モデリング）・ドローン測量・3Dプリント建設への建設業採用を分析した研究群。零細中小企業の多い産業構造・技術習熟コスト・発注者要件が採用規定因として確認されている。英国BIM義務化政策の影響研究も含まれる。','建設産業のデジタル化政策と公共調達基準設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','建設テクノロジー採用研究','2011','meso','adoption','industry_structure_adoption','["Eastman, C.", "Succar, B.", "Aranda-Mena, G."]','["Eastman et al. (2011) BIM Handbook", "Succar (2009) BIM framework"]','BIM,デジタル建設,建設テクノロジー,3Dプリント建設','BIM,digital construction,construction technology,3D printing construction'),
('inno_diff_273','レガシーIT脱却（マイグレーション）意思決定研究','Legacy IT Migration Decision-Making Research','30〜40年前のレガシーシステム（COBOL基幹系・オンプレミスERP等）のクラウド・マイクロサービスへの移行採用を分析した研究群。技術的負債・組織知識の喪失リスク・経営者リスク認知・ベンダーサポート終了が意思決定に影響することが確認されている。','金融機関・行政機関のレガシーモダナイゼーション戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ITモダナイゼーション採用研究','2015','meso','adoption','legacy_dependency_adoption','["Khadka, K.", "Vasantharajan, S.", "Avgeriou, P."]','["Khadka et al. (2014) Legacy software evolution", "Avgeriou et al. (2021) Technical debt"]','レガシーIT,システム移行,技術的負債,クラウド移行','legacy IT,system migration,technical debt,cloud migration'),
('inno_diff_274','製薬業界における電子臨床試験技術採用','Electronic Clinical Trial Technology Adoption in Pharmaceutical Industry','EDC（電子データ収集）・eConsent・DCT（分散型臨床試験）・ウェアラブルによるリモートモニタリングの製薬企業採用を分析した研究群。規制当局（FDA・EMA）との整合性・データ品質・患者参加率向上が主要テーマとなっている。','製薬企業の治験効率化戦略と規制当局のデジタルヘルス政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','製薬・臨床試験技術採用研究','2015','meso','adoption','regulatory_alignment_adoption','["Bhatt, A.", "Inan, O.T.", "Haendel, M.A."]','["Bhatt (2011) Clinical trials evolution", "Inan et al. (2017) Wearable clinical trials"]','臨床試験,EDC,分散型試験,電子同意','clinical trials,EDC,decentralized trials,eConsent'),
('inno_diff_275','社会信用システム採用の市民研究（中国事例）','Citizen Research on Social Credit System Adoption: China Case','中国の社会信用体系への市民・企業の態度と採用行動を分析した研究群。政府信頼・プライバシー感受性・体制正当性認知・罰則への態度が受容に影響することが示された。比較政治学・監視研究の観点からの批判的分析も含まれる。','AIガバナンス・デジタル権威主義研究・プライバシー権政策に影響を与えた重要事例研究を提供した。','diffusion_adoption_user','C_processes','デジタルガバナンス採用研究','2018','meso','adoption','institutional_legitimacy_adoption','["Hvistendahl, M.", "Kostka, G.", "Chin, J."]','["Kostka (2019) Social credit survey", "Chin & Lin (2017) Social credit overview"]','社会信用システム,中国,デジタルガバナンス,プライバシー','social credit system,China,digital governance,privacy'),
('inno_diff_276','ライドシェア採用の多国間比較研究','Multi-Country Comparative Study on Ride-Sharing Adoption','UberやDiDi・Grabなどライドシェアサービスの採用を先進国・新興国で比較分析した研究群。都市インフラ状況・規制環境・タクシー産業との競合・文化的モビリティ規範が採用速度の差異を説明することが示された。','都市交通政策・プラットフォーム規制・モビリティサービス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','シェアリングモビリティ採用研究','2016','meso','adoption','urban_mobility_adoption','["Rayle, L.", "Shaheen, S.", "Hall, J.D."]','["Rayle et al. (2016) Ridesourcing adoption", "Hall & Krueger (2018) Uber driver-partners"]','ライドシェア,Uber,都市交通,モビリティ','ride-sharing,Uber,urban transportation,mobility'),
('inno_diff_277','医療診断AI採用の医師研究','Physician Research on Medical Diagnostic AI Adoption','画像診断AI（放射線科・病理科）・心電図AI・スクリーニングAIへの医師採用を分析した研究群。診断精度への信頼・責任の所在・医師-AI協働プロセス・電子カルテ統合が採用規定因として確認されている。','医療AI規制政策・診療ガイドライン整備・医学教育カリキュラム改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','医療AI採用研究','2018','meso','adoption','clinical_trust_adoption','["Topol, E.J.", "Liu, Y.", "Rajpurkar, P."]','["Topol (2019) Deep Medicine", "Liu et al. (2019) AI in radiology"]','医療診断AI,放射線AI,医師採用,AI信頼','medical diagnostic AI,radiology AI,physician adoption,AI trust'),
('inno_diff_278','ランダム化比較試験（RCT）による採用促進介入研究','RCT-Based Intervention Research on Adoption Promotion','採用促進施策（情報提供・補助金・ナッジ・ピアレファレンス）の効果をRCTで検証した研究群。情報不確実性の解消・社会的証明・コミットメントデバイスが採用率向上に有効であることが示された。開発経済学・行動公共政策との融合が進んでいる。','公共採用促進政策のエビデンス基盤を構築し、費用対効果の高い介入設計に貢献した。','diffusion_adoption_user','C_processes','採用促進・行動介入研究','2010','meso','adoption','behavioral_intervention_adoption','["Dupas, P.", "Cohen, J.", "Karlan, D."]','["Dupas (2014) Health product adoption RCT", "Cohen & Dupas (2010) Free distribution RCT"]','RCT,採用促進,ナッジ,社会的証明','RCT,adoption promotion,nudge,social proof'),
('inno_diff_279','コラボレーションツール採用の分散チーム研究','Distributed Team Research on Collaboration Tool Adoption','Slack・Microsoft Teams・Zoom・Notionなどコラボレーションツールの分散チーム採用を分析した研究群。タスク-メディアフィット理論・メディア豊かさ理論・社会的プレゼンス理論が統合的に用いられる。ツールの多様化による「ツール疲れ」も新たな研究テーマとなっている。','分散組織のデジタルワークプレイス設計と企業ソフトウェア調達戦略に貢献した。','diffusion_adoption_user','C_processes','コラボレーションツール採用研究','2013','meso','adoption','media_fit_adoption','["Daft, R.L.", "Lengel, R.H.", "Kayworth, T.R."]','["Daft & Lengel (1986) Organizational information requirements", "Kayworth & Leidner (2002) Virtual teams"]','コラボレーションツール,Slack,分散チーム,ツール疲れ','collaboration tools,Slack,distributed teams,tool fatigue'),
('inno_diff_280','スマートウォッチ採用とデジタルウェルネス行動','Smartwatch Adoption and Digital Wellness Behavior','Apple Watch・Garmin・Fitbitなどスマートウォッチの採用とその後の健康行動変容を分析した研究群。フィードバック活用度・健康目標明確性・ソーシャル比較・機能過多による離脱が研究テーマとなっている。','ウェアラブルヘルスケア製品設計と健康促進政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマートウォッチ採用研究','2015','micro','adoption','feedback_loop_adoption','["Cadmus-Bertram, L.A.", "Marcus, B.H.", "Patterson, R.E."]','["Cadmus-Bertram et al. (2015) Fitbit", "Piwek et al. (2016) Consumer wearables"]','スマートウォッチ,フィットネストラッカー,健康行動,フィードバック','smartwatch,fitness tracker,health behavior,feedback'),
('inno_diff_281','プラットフォームコオペティション下での採用戦略','Adoption Strategy under Platform Coopetition','同一プラットフォームエコシステム内で競合する補完的製品・サービスの採用戦略を分析した研究群。プラットフォームオーナーによるエンベロープメント（囲い込み）リスク・コオペティション均衡・パートナー信頼が採用意思決定に影響することが示された。','プラットフォームパートナーの製品採用戦略と競争法規制に理論的根拠を提供した。','diffusion_adoption_user','C_processes','プラットフォーム競争・採用研究','2010','meso','adoption','coopetition_adoption','["Brandenburger, A.M.", "Nalebuff, B.J.", "Gawer, A."]','["Brandenburger & Nalebuff (1996) Co-opetition", "Gawer & Cusumano (2008) Platform leaders"]','コオペティション,プラットフォーム戦略,補完財採用,エンベロープメント','coopetition,platform strategy,complementary adoption,envelopment'),
('inno_diff_282','消費者向けAIアシスタント採用の長期研究','Longitudinal Research on Consumer AI Assistant Adoption','Siri・Google Assistant・Cortana・ChatGPTなどAIアシスタントの長期的採用・継続・離脱行動を追跡した研究群。初期採用から習慣化・機能拡張・信頼崩壊（誤回答体験）・プライバシー懸念が長期採用軌跡を規定することが示された。','AI製品のロードマップ設計とユーザーリテンション戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AIアシスタント採用研究','2018','micro','adoption','long_term_trust_adoption','["Luger, E.", "Sellen, A.", "Porcheron, M."]','["Luger & Sellen (2016) Conversational agents", "Porcheron et al. (2018) Voice interfaces home"]','AIアシスタント,長期採用,信頼崩壊,習慣化','AI assistant,long-term adoption,trust breakdown,habituation'),
('inno_diff_283','宇宙技術採用の商業市場研究（New Space）','Commercial Market Research on Space Technology Adoption: New Space','小型衛星・商業打ち上げサービス・衛星インターネット（Starlink等）への企業・政府採用を分析した研究群。打ち上げコスト低下・規制整備・衛星コンステレーション信頼性・地政学的リスクが採用規定因として確認されている。','商業宇宙産業政策・軍民両用技術戦略・グローバル通信インフラ設計に貢献した。','diffusion_adoption_user','C_processes','宇宙産業採用研究','2018','meso','adoption','emerging_space_adoption','["Bryce, S.", "Caceres, R.S.", "Foust, J."]','["Bryce Space and Technology (2020) New Space Index", "Foust (2021) Commercial launch market"]','New Space,小型衛星,Starlink,商業宇宙','New Space,small satellites,Starlink,commercial space'),
('inno_diff_284','マイクロモビリティ採用研究（電動キックボード）','Micro-Mobility Adoption Research: E-Scooters','シェア電動キックボード・シェア電動自転車への都市住民採用を分析した研究群。安全懸念・歩道走行問題・駐車マナー・天候依存性が採用障壁として確認されている。都市交通政策との統合と採用後の自動車代替効果も重要テーマとなっている。','都市モビリティ政策・公共空間設計・マイクロモビリティ規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','マイクロモビリティ採用研究','2018','micro','adoption','urban_transport_adoption','["McKenzie, G.", "Laa, B.", "Fitt, H."]','["McKenzie (2019) Spatiotemporal e-scooter", "Laa & Litzinger (2020) E-scooter adoption"]','電動キックボード,マイクロモビリティ,都市交通,シェアモビリティ','e-scooter,micro-mobility,urban transport,shared mobility'),
('inno_diff_285','オンライン医療予約・診療記録アクセス採用研究','Online Medical Appointment and Health Record Access Adoption Research','病院ウェブポータル・スマートフォンアプリによるオンライン予約・診療記録参照への患者採用を分析した研究群。年齢・ITリテラシー・慢性疾患有無・医療機関との関係性が採用規定因として確認されている。','患者-医療者コミュニケーション改善と医療DX政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','患者デジタルアクセス採用研究','2012','micro','adoption','patient_empowerment_adoption','["Ammenwerth, E.", "Schnell-Inderst, P.", "Hoerbst, A."]','["Ammenwerth et al. (2012) Patient EHR access", "Hoerbst & Ammenwerth (2010) EHR review"]','オンライン医療予約,診療記録,患者採用,医療DX','online medical booking,health records,patient adoption,healthcare DX'),
('inno_diff_286','クリエイティブAIツール採用の専門家研究','Professional Research on Creative AI Tool Adoption','Midjourney・Stable Diffusion・Sora・Adobe Fireflyなど生成AI画像・動画ツールへのクリエイター（デザイナー・映像制作者・広告クリエイター）採用を分析した研究群。著作権・作品アイデンティティ・品質不確実性・ワークフロー統合が採用規定因として確認されている。','クリエイティブ産業の生成AI活用政策と著作権制度改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','生成AIクリエイティブ採用研究','2022','micro','adoption','creative_identity_adoption','["Oppenlaender, J.", "Epstein, Z.", "Elgammal, A."]','["Oppenlaender (2022) Creativity AI", "Epstein et al. (2023) Art vs AI perceptions"]','生成AI,クリエイターAI,著作権,ワークフロー統合','generative AI,creative AI,copyright,workflow integration'),
('inno_diff_287','デジタル通関・貿易手続き採用研究','Digital Customs and Trade Procedure Adoption Research','シングルウィンドウ・電子通関・デジタル原産地証明など貿易手続きデジタル化への企業採用を分析した研究群。規制整合性・IT インフラ・信頼・貿易パートナーとの相互運用性が採用規定因として確認されている。WTO貿易円滑化協定との関係も重要テーマとなっている。','貿易デジタル化政策と税関行政改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','貿易デジタル化採用研究','2013','meso','adoption','trade_facilitation_adoption','["Weerakkody, V.", "Irani, Z.", "Al-Busaidy, M."]','["Weerakkody et al. (2011) E-government trade", "Al-Busaidy & Weerakkody (2009) Oman eGov"]','デジタル通関,シングルウィンドウ,貿易手続き,相互運用性','digital customs,single window,trade procedures,interoperability'),
('inno_diff_288','医薬品Eコマース採用の消費者研究','Consumer Research on Pharmaceutical E-Commerce Adoption','オンライン薬局・処方薬デリバリーサービスへの消費者採用を分析した研究群。医薬品の偽造品懸念・処方箋提出の利便性・薬剤師との対面相談需要・規制整合性が採用規定因として確認されている。COVID-19による急速採用とその後の定着も研究されている。','医薬品Eコマース規制政策と薬局デジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','医薬品Eコマース採用研究','2019','micro','adoption','safety_concern_adoption','["Fittler, A.", "Bősze, G.", "Vida, R.G."]','["Fittler et al. (2013) Online pharmacy safety", "Vida et al. (2019) Pharmacy e-commerce"]','オンライン薬局,処方薬デリバリー,偽造品,医薬品採用','online pharmacy,prescription delivery,counterfeit,pharmaceutical adoption'),
('inno_diff_289','水産養殖技術採用の実証研究','Empirical Research on Aquaculture Technology Adoption','循環型養殖（RAS）・ウェアラブルセンサー・飼料最適化AIなど水産養殖技術の採用を分析した研究群。初期投資コスト・技術知識習得・市場アクセス・環境規制が採用規定因として確認されている。持続可能な水産業政策との接続も重要テーマとなっている。','水産養殖産業の技術政策と食料安全保障戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','水産業技術採用研究','2015','meso','adoption','technical_knowledge_adoption','["Bregnballe, J.", "Bjørnstad, A.", "Asche, F."]','["Bregnballe (2015) Aquaculture guide", "Asche et al. (2021) Salmon farming technology"]','水産養殖,RAS,循環型養殖,持続可能水産業','aquaculture,RAS,recirculating systems,sustainable fisheries'),
('inno_diff_290','エネルギーコミュニティ採用研究','Energy Community Adoption Research','再生可能エネルギーの共同所有・地域電力自給自足・ピアツーピア電力取引への市民参加採用を分析した研究群。コミュニティ帰属感・エネルギー民主主義価値・経済的メリット・行政サポートが採用規定因として確認されている。EU再生可能エネルギー指令（RED II）との接続も議論されている。','エネルギーコミュニティ政策と地域分散型電力システム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','エネルギーコミュニティ採用研究','2016','meso','adoption','community_identity_adoption','["Bauwens, T.", "Gotchev, B.", "Holstenkamp, L."]','["Bauwens et al. (2016) Community energy", "Holstenkamp & Kahla (2016) Energy cooperatives"]','エネルギーコミュニティ,再生可能エネルギー共同所有,P2P電力,エネルギー民主主義','energy community,renewable energy co-ownership,P2P energy,energy democracy'),
('inno_diff_291','3Dバイオプリンティング採用の医療研究','Medical Research on 3D Bioprinting Adoption','臓器・組織・薬物送達システムへの3Dバイオプリンティング採用を分析した研究群。細胞生存率・規制承認プロセス・生産スケーラビリティ・倫理的懸念が採用規定因として確認されている。','再生医療政策と医療デバイス規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','バイオテクノロジー採用研究','2017','meso','adoption','regulatory_science_adoption','["Murphy, S.V.", "Atala, A.", "Groll, J."]','["Murphy & Atala (2014) 3D bioprinting organs", "Groll et al. (2018) Biofabrication"]','3Dバイオプリンティング,臓器プリント,再生医療,規制科学','3D bioprinting,organ printing,regenerative medicine,regulatory science'),
('inno_diff_292','オートメーション採用と技術的失業の実証研究','Empirical Research on Automation Adoption and Technological Unemployment','製造業・物流・小売・金融でのオートメーション採用と職種消滅・変容の実証研究群。Frey & Osborne の職業自動化確率推定の批判的検証・更新や、採用タイミングと技術的失業の地域差分析が含まれる。','雇用政策・社会保障制度改革・技術教育投資戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','自動化採用・労働市場研究','2013','macro','adoption','technological_unemployment','["Frey, C.B.", "Osborne, M.A.", "Dauth, W."]','["Frey & Osborne (2013) Future of employment", "Dauth et al. (2021) Robots and workers Germany"]','自動化採用,技術的失業,職業代替,雇用影響','automation adoption,technological unemployment,job displacement,employment impact'),
('inno_diff_293','ERP採用の中小企業研究','SME Research on ERP System Adoption','中小企業（SME）によるERP（Enterprise Resource Planning）システム採用の規定因・実装失敗要因・成果を分析した研究群。経営資源制約・ベンダーサポート依存・プロセス再設計抵抗・クラウドERPへの移行が主要テーマとなっている。','中小企業のIT投資意思決定と中小企業支援政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ERP採用研究','2001','meso','adoption','resource_constraint_adoption','["Deep, A.", "Guttridge, P.", "Dani, S."]','["Deep et al. (2008) ERP SME", "Laukkanen et al. (2007) ERP barriers SME"]','ERP,中小企業,システム採用,クラウドERP','ERP,SME,system adoption,cloud ERP'),
('inno_diff_294','コンタクトレスペイメント採用研究（COVID-19以降）','Post-COVID-19 Contactless Payment Adoption Research','NFC・QRコード決済・生体認証決済などコンタクトレス決済の採用をCOVID-19衛生動機の観点から分析した研究群。衛生意識・速度・プライバシー・高齢者のデジタル格差が採用規定因として確認されている。','デジタル決済政策とキャッシュレス社会推進戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル決済採用研究','2020','micro','adoption','hygiene_motivated_adoption','["Pal, D.", "Funilkul, S.", "Charoenkitkarn, V."]','["Pal et al. (2021) Contactless payment COVID", "Charoenkitkarn et al. (2021) NFC payment"]','コンタクトレス決済,NFC,QRコード決済,衛生意識','contactless payment,NFC,QR code payment,hygiene awareness'),
('inno_diff_295','ソーシャルロボット採用の高齢者ケア研究','Elderly Care Research on Social Robot Adoption','Pepper・NAO・PARO（アザラシ型ロボット）など社会的ロボットの高齢者施設採用を分析した研究群。介護職員の受容・居住者の感情的反応・管理者の費用便益判断・倫理的懸念が採用規定因として確認されている。','高齢者ケア政策とソーシャルロボティクス製品設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','高齢者ケアロボット採用研究','2016','meso','adoption','emotional_technology_adoption','["Heerink, M.", "Kröse, B.", "Wielinga, B."]','["Heerink et al. (2010) UTAUT robots", "Broekens et al. (2009) Social robots elderly"]','ソーシャルロボット,高齢者ケア,PARO,介護ロボット','social robot,elderly care,PARO,care robot'),
('inno_diff_296','都市農業技術採用研究（垂直農場・コンテナファーム）','Urban Agriculture Technology Adoption Research: Vertical Farms and Container Farms','垂直農業・コンテナ農場・植物工場への事業者採用と消費者受容を分析した研究群。エネルギーコスト・水使用効率・立地適性・ローカルフード需要が採用規定因として確認されている。食料安全保障・都市食料システム政策との接続も議論されている。','都市農業政策・スマートシティ食料戦略・フードテック投資に実証的根拠を提供した。','diffusion_adoption_user','C_processes','都市農業採用研究','2018','meso','adoption','local_food_adoption','["Benke, K.", "Tomkins, B.", "Al-Chalabi, M."]','["Benke & Tomkins (2017) Vertical farming", "Al-Chalabi (2015) Vertical farming profitability"]','垂直農業,都市農業,植物工場,ローカルフード','vertical farming,urban agriculture,plant factory,local food'),
('inno_diff_297','デジタルアイデンティティ管理技術採用研究','Digital Identity Management Technology Adoption Research','SSI（Self-Sovereign Identity）・分散型ID（DID）・生体認証IDへの企業・市民採用を分析した研究群。プライバシー制御・相互運用性・規制準拠・ユーザビリティが採用規定因として確認されている。EUデジタルIDウォレット（EIDAS2.0）の実装研究も含まれる。','デジタルID政策と個人情報保護制度設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルID採用研究','2019','meso','adoption','identity_sovereignty_adoption','["Preukschat, A.", "Reed, D.", "Zwitter, A."]','["Preukschat & Reed (2021) SSI book", "Zwitter et al. (2020) SSI in healthcare"]','デジタルアイデンティティ,SSI,DID,生体認証','digital identity,SSI,DID,biometric'),
('inno_diff_298','宇宙由来データ（Earth Observation）採用研究','Earth Observation Data Adoption Research','Copernicus・Landsat・商業衛星データの農業・防災・都市計画・金融分野での採用を分析した研究群。データ解析能力・コスト・更新頻度・ドメイン統合難易度が採用規定因として確認されている。','衛星データ利活用政策と地球観測産業の民主化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','衛星データ採用研究','2015','meso','adoption','data_capability_adoption','["Straub, C.", "Vermote, E.", "Pesaresi, M."]','["Straub et al. (2017) Copernicus adoption", "Pesaresi et al. (2016) Global Human Settlement Layer"]','地球観測,衛星データ,Copernicus,リモートセンシング','Earth observation,satellite data,Copernicus,remote sensing'),
('inno_diff_299','量子暗号・ポスト量子暗号採用の組織研究','Organizational Research on Quantum Cryptography and Post-Quantum Cryptography Adoption','量子鍵配送（QKD）とNISTポスト量子暗号標準への組織的移行を分析した研究群。移行コスト・後方互換性・暗号アジリティ・量子コンピュータ脅威タイムラインへの不確実性が採用規定因として確認されている。','サイバーセキュリティ移行計画と情報セキュリティ規制改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','量子セキュリティ採用研究','2020','meso','adoption','security_migration_adoption','["Chen, L.", "Jordan, S.", "Liu, Y.K."]','["NIST (2022) Post-quantum standards", "Chen et al. (2016) NIST PQC report"]','量子暗号,ポスト量子暗号,QKD,暗号アジリティ','quantum cryptography,post-quantum cryptography,QKD,crypto agility'),
('inno_diff_300','生成AIコーディングツール採用の開発者研究','Developer Research on Generative AI Coding Tool Adoption','GitHub Copilot・Cursor・Codex・Claude APIなど生成AIコーディングアシスタントへのソフトウェア開発者採用を分析した研究群。生産性効果・コード品質・セキュリティリスク・知的財産懸念・スキル劣化不安が採用規定因として確認されている。','ソフトウェアエンジニアリング教育・開発ツール市場戦略・知的財産法改革に貢献した。','diffusion_adoption_user','C_processes','生成AIコーディング採用研究','2022','micro','adoption','productivity_adoption','["Ziegler, A.", "Kalliamvakou, E.", "Vaithilingam, P."]','["Ziegler et al. (2022) GitHub Copilot productivity", "Vaithilingam et al. (2022) Copilot user study"]','生成AIコーディング,GitHub Copilot,開発者採用,コード品質','generative AI coding,GitHub Copilot,developer adoption,code quality');
